```javascript
/**
 * Perplexity Research Query Manager
 * Handles decomposition and execution of multi-part research questions
 */

class ResearchQueryManager {
  constructor(apiKey) {
    this.apiKey = apiKey;
    this.baseUrl = 'https://api.perplexity.ai/chat/completions';
    this.queries = [];
    this.results = [];
  }

  /**
   * Decompose a complex question into atomic queries
   */
  decompose(question) {
    const components = this.identifyComponents(question);
    const atomicQueries = components.map(c => this.toAtomicQuery(c));
    this.queries = atomicQueries;
    return {
      original: question,
      components: components,
      atomicQueries: atomicQueries
    };
  }

  identifyComponents(question) {
    // Split by common separators
    const separators = /,\s*(?:and|or)?\s*/gi;
    return question.split(separators).map(s => s.trim()).filter(s => s.length > 0);
  }

  toAtomicQuery(component) {
    // Clean and format for search
    return component
      .replace(/^(what|how|why|when|where|who)\s+/i, '')
      .replace(/\?/g, '')
      .trim();
  }

  /**
   * Execute queries with priority ordering
   */
  async executeQueries(queryData, options = {}) {
    const { parallel = false, delayMs = 1000 } = options;
    const results = [];
    const queries = queryData.prioritized || queryData.atomicQueries;

    if (parallel) {
      // Execute all queries simultaneously
      const responses = await Promise.all(
        queries.map(q => this.executeSingleQuery(q))
      );
      return responses;
    } else {
      // Execute sequentially with delay
      for (const query of queries) {
        const result = await this.executeSingleQuery(query);
        results.push(result);
        if (queries.indexOf(query) < queries.length - 1) {
          await this.delay(delayMs);
        }
      }
      return results;
    }
  }

  async executeSingleQuery(query) {
    try {
      const response = await fetch(this.baseUrl, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: 'sonar',
          messages: [{ role: 'user', content: query }],
          max_tokens: 1000
        })
      });

      const data = await response.json();
      return {
        query: query,
        status: 'success',
        answer: data.choices?.[0]?.message?.content || '',
        citations: data.citations || []
      };
    } catch (error) {
      return {
        query: query,
        status: 'error',
        error: error.message
      };
    }
  }

  /**
   * Synthesize results into coherent response
   */
  synthesize(results, originalQuestion) {
    const synthesis = {
      originalQuestion: originalQuestion,
      findings: [],
      sourceMapping: {},
      gaps: []
    };

    results.forEach((result, index) => {
      if (result.status === 'success') {
        synthesis.findings.push({
          queryNumber: index + 1,
          query: result.query,
          summary: result.answer.substring(0, 200) + '...',
          sources: result.citations
        });
        result.citations.forEach(citation => {
          synthesis.sourceMapping[citation] = result.query;
        });
      } else {
        synthesis.gaps.push({
          query: result.query,
          error: result.error
        });
      }
    });

    return synthesis;
  }

  delay(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

// Usage Example
async function main() {
  const manager = new ResearchQueryManager(process.env.PPLX_API_KEY);

  // Step 1: Decompose complex question
  const decomposition = manager.decompose(
    "What are the environmental effects of electric vehicles, and how do they compare to traditional gasoline cars over their lifecycle?"
  );

  console.log('Decomposed Queries:');
  console.log(decomposition.atomicQueries);

  // Step 2: Execute with priority
  const results = await manager.executeQueries(
    { atomicQueries: decomposition.atomicQueries },
    { parallel: false, delayMs: 1500 }
  );

  // Step 3: Synthesize findings
  const synthesis = manager.synthesize(
    results,
    "What are the environmental effects of electric vehicles, and how do they compare to traditional gasoline cars over their lifecycle?"
  );

  console.log('Synthesis:');
  console.log(JSON.stringify(synthesis, null, 2));
}

// Export for module usage
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { ResearchQueryManager };
}
```



## Common Mistakes

- Submitting compound questions without decomposition, expecting the AI to infer all sub-topics automatically
- Creating atomic queries that are still too broad (e.g., "everything about X") instead of focused on specific aspects
- Forgetting to check for ambiguous terminology before searching, leading to mixed or irrelevant results
- Executing queries in random order without considering logical dependencies between sub-topics
- Not tracking which source supports which claim during reconstruction, making citation difficult
- Over-decomposing questions into trivial queries that lack context for meaningful answers
- Failing to revisit and refine atomic queries based on initial results that reveal new aspects
- Combining results from different atomic queries without acknowledging where information might conflict


## Best Practices

- Always read your research question aloud and identify natural pauses or comma breaks—these often indicate separate sub-topics
- Start each atomic query with specific nouns and verbs rather than leading with question words for more targeted results
- Include time periods, geographic regions, or other scope-limiting terms in each atomic query to reduce ambiguity
- Maintain a research log that maps each atomic query to its results and sources for traceability
- Execute foundational queries first to build context before tackling more specific sub-questions
- When results from different atomic queries seem contradictory, create additional queries to resolve the discrepancy
- Save successful query structures as templates for similar future research questions
- Review the citations and sources from each atomic query before synthesizing to ensure quality and relevance

