        }
        result["identified_components"].append(component)
        result["suggested_atomic_queries"].append(f'"{part.strip()}"')

    # Identify potential ambiguous terms
    ambiguous = ["effect", "impact", "role", "benefits", "costs", "AI", "system"]
    for term in ambiguous:
        if term in cleaned:
            result["ambiguous_terms"].append(term)

    # Suggest priority order (foundational first)
    result["priority_order"] = [f"Query {i+1}" for i in range(len(parts))]

    return result

def identify_type(text: str) -> str:
    """Identify the type of question component."""
    if "compare" in text or "versus" in text:
        return "comparative"
    elif "effect" in text or "impact" in text:
        return "causal"
    elif "what" in text or "how" in text:
        return "descriptive"
    elif "why" in text:
        return "explanatory"
    return "general"

def main():
    # Example complex questions to analyze
    examples = [
        "How did the Industrial Revolution affect women's labor roles in England, and what were the long-term consequences?",
        "Compare renewable energy adoption in Germany versus Denmark, and explain the economic factors involved.",
        "What are the effects of artificial intelligence on healthcare costs, patient outcomes, and medical professional roles?"
