/**
 * Perplexity Research Query Manager
 * Handles decomposition and execution of multi-part research questions
 */

class ResearchQueryManager {
  constructor(apiKey) {
    this.apiKey = apiKey;
    this.baseUrl = 'https://api.perplexity.ai/chat/completions';
    this.queries = [];
    this.results = [];
  }

  /**
   * Decompose a complex question into atomic queries
   */
  decompose(question) {
    const components = this.identifyComponents(question);
    const atomicQueries = components.map(c => this.toAtomicQuery(c));
    this.queries = atomicQueries;
    return {
      original: question,
      components: components,
      atomicQueries: atomicQueries
    };
  }

  identifyComponents(question) {
    // Split by common separators
    const separators = /,\s*(?:and|or)?\s*/gi;
    return question.split(separators).map(s => s.trim()).filter(s => s.length > 0);
  }

  toAtomicQuery(component) {
    // Clean and format for search
    return component
      .replace(/^(what|how|why|when|where|who)\s+/i, '')
      .replace(/\?/g, '')
      .trim();
  }

  /**
   * Execute queries with priority ordering
   */
  async executeQueries(queryData, options = {}) {
    const { parallel = false, delayMs = 1000 } = options;
    const results = [];
    const queries = queryData.prioritized || queryData.atomicQueries;

    if (parallel) {
      // Execute all queries simultaneously
      const responses = await Promise.all(
        queries.map(q => this.executeSingleQuery(q))
      );
      return responses;
    } else {
      // Execute sequentially with delay
      for (const query of queries) {
        const result = await this.executeSingleQuery(query);
        results.push(result);
        if (queries.indexOf(query) < queries.length - 1) {
          await this.delay(delayMs);
        }
      }
      return results;
    }
  }

  async executeSingleQuery(query) {
    try {
      const response = await fetch(this.baseUrl, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: 'sonar',
          messages: [{ role: 'user', content: query }],
          max_tokens: 1000
        })
      });

      const data = await response.json();
      return {
        query: query,
        status: 'success',
        answer: data.choices?.[0]?.message?.content || '',
        citations: data.citations || []
      };
    } catch (error) {
      return {
        query: query,
        status: 'error',
        error: error.message
      };
    }
  }

  /**
   * Synthesize results into coherent response
   */
  synthesize(results, originalQuestion) {
    const synthesis = {
      originalQuestion: originalQuestion,
      findings: [],
      sourceMapping: {},
      gaps: []
    };

    results.forEach((result, index) => {
      if (result.status === 'success') {
        synthesis.findings.push({
          queryNumber: index + 1,
          query: result.query,
          summary: result.answer.substring(0, 200) + '...',
          sources: result.citations
        });
        result.citations.forEach(citation => {
          synthesis.sourceMapping[citation] = result.query;
        });
      } else {
        synthesis.gaps.push({
          query: result.query,
          error: result.error
        });
      }
    });

    return synthesis;
  }

  delay(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

// Usage Example
async function main() {
  const manager = new ResearchQueryManager(process.env.PPLX_API_KEY);

  // Step 1: Decompose complex question
  const decomposition = manager.decompose(
    "What are the environmental effects of electric vehicles, and how do they compare to traditional gasoline cars over their lifecycle?"
  );

